    "excerpt": "---\nname: planning-with-files-ar\ndescription: \"نظام تخطيط الملفات بنمط Manus لتنظيم وتتبع تقدم المهام المعقدة. ينشئ ملفات task_plan.md و findings.md و progress.md. يُستخدم عند طلب التخطيط أو تحليل المهام أو تنظيم المشاريع أو تتبع التقدم أو الخطط متعددة الخطوات. يدعم الاستعادة التلقائية للجلسة بعد /clear. كلمات التشغيل: تخطيط المهام، إدارة المشاريع، خطة العمل، تحليل المهام، تنظيم المشروع، تتبع التقدم، خطة متعددة الخطوات، ساعدني في التخطيط، تحليل المشروع\"\nuser-invocable: true\nallowed-tools: \"Read Write Edit Bash Glob Grep\"\nhooks:\n  UserPromptSubmit:\n    - hooks:\n        - type: command\n          command: \"RESOLVED=\\\"\\\"; SCOPE=\\\"\\\"; SLUG_RE='^[A-Za-z0-9_][A-Za-z0-9._-]*$'; if [ -n \\\"${PLAN_ID:-}\\\" ] && printf \\\"%s\\\" \\\"$PLAN_ID\\\" | grep -Eq \\\"$SLUG_RE\\\" && [ -d \\\".planning/${PLAN_ID}\\\" ]; then RESOLVED=\\\".planning/${PLAN_ID}\\\"; SCOPE=\\\"scoped\\\"; elif [ -f .planning/.active_plan ]; then AP=$(tr -d '\\\\r\\\\n[:space:]' < .planning/.active_plan 2>/dev/null); if [ -n \\\"$AP\\\" ] && printf \\\"%s\\\" \\\"$AP\\\" | grep -Eq \\\"$SLUG_RE\\\" && [ -d \\\".planning/${AP}\\\" ]; then RESOLVED=\\\".planning/${AP}\\\"; SCOPE=\\\"scoped\\\"; fi; fi; if [ -z \\\"$RESOLVED\\\" ] && [ -d .planning ]; then NEWEST=\\\"\\\"; NEWEST_MT=0; for d in .planning/*/; do d=\\\"${d%/}\\\"; n=$(basename \\\"$d\\\"); case \\\"$n\\\" in .*) continue;; esac; printf \\\"%s\\\" \\\"$n\\\" | grep -Eq \\\"$SLUG_RE\\\" || continue; [ -f \\\"$d/task_plan.md\\\" ] || continue; m=$(stat -c '%Y' \\\"$d\\\" 2>/dev/null || stat -f '%m' \\\"$d\\\" 2>/dev/null || date -r \\\"$d\\\" +%s 2>/dev/null || echo 0); if [ \\\"$m\\\" -gt \\\"$NEWEST_MT\\\" ] 2>/dev/null; then NEWEST_MT=\\\"$m\\\"; NEWEST=\\\"$d\\\"; fi; done; [ -n \\\"$NEWEST\\\" ] && { RESOLVED=\\\"$NEWEST\\\"; SCOPE=\\\"scoped\\\"; }; fi; if [ -z \\\"$RESOLVED\\\" ] && [ -f task_plan.md ]; then RESOLVED=\\\".\\\"; SCOPE=\\\"root\\\"; fi; [ -z \\\"$RESOLVED\\\" ] && exit 0; if [ \\\"$SCOPE\\\" = \\\"root\\\" ]; then PLAN_FILE=\\\"task_plan.md\\\"; PROGRESS_FILE=\\\"progress.md\\\"; ATTEST=\\\"\\\"; [ -f .plan-attestation ] && ATTEST=$(tr -d '\\\\r\\\\n[:space:]' < .plan-attestation 2>/dev/null); e",
